// Reshape three sheets into the build_project JSON spec.
const tasksRows       = $('Read Tasks sheet').all().map(i => i.json);
const resourceRows    = $('Read Resources sheet').all().map(i => i.json);
const assignmentRows  = $('Read Assignments sheet').all().map(i => i.json);

// Tasks: expected columns id, name, outline_level, duration, predecessors, EV_method, milestone, deadline
const tasks = tasksRows.filter(r => r.id).map(r => {
  const t = {
    id: Number(r.id),
    name: r.name,
    outline_level: Number(r.outline_level || 1)
  };
  if (String(r.summary).toLowerCase() === 'true') t.summary = true;
  if (String(r.milestone).toLowerCase() === 'true') t.milestone = true;
  if (r.duration) t.duration = String(r.duration);
  if (r.deadline) t.deadline = r.deadline;
  if (r.EV_method) t.earned_value_method = r.EV_method;
  if (r.percent_complete) t.percent_complete = Number(r.percent_complete);
  // predecessors: "3FS+0d, 4SS-1d" → [{id:3,type:FS,lag:0d}, {id:4,type:SS,lag:-1d}]
  if (r.predecessors) {
    t.predecessors = String(r.predecessors).split(',').map(s => s.trim()).filter(Boolean).map(token => {
      const m = token.match(/^(\d+)([A-Za-z]{2})?([+\-]?[\d.]+[a-z]+)?$/);
      return m ? { id: Number(m[1]), type: m[2] || 'FS', lag: m[3] || '0d' } : null;
    }).filter(Boolean);
  }
  return t;
});

const resources = resourceRows.filter(r => r.id).map(r => ({
  id: Number(r.id),
  name: r.name,
  type: (r.type || 'WORK').toUpperCase(),
  max_units: r.max_units ? Number(r.max_units) : 100,
  standard_rate: r.standard_rate || undefined,
  material_label: r.material_label || undefined
}));

const assignments = assignmentRows.filter(r => r.task_id).map(r => ({
  task_id: Number(r.task_id),
  resource_id: Number(r.resource_id),
  units: r.units ? Number(r.units) : 100,
  work: r.work || undefined
}));

const spec = {
  project: {
    title: $vars.PROJECT_TITLE || 'Generated Project',
    start_date: $vars.START_DATE || new Date().toISOString().slice(0,10),
    default_calendar: 'Standard',
    minutes_per_day: 480,
    minutes_per_week: 2400,
    currency_symbol: '$',
    currency_code: $vars.CURRENCY || 'COP',
    default_task_ev_method: 'PERCENT_COMPLETE'
  },
  resources,
  tasks,
  assignments,
  options: { save_baseline: true }
};

return [{ json: { spec } }];
